#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

const LIMIT = 10;
const WINDOW_MS = 1000;

type ClientWindow = {
  windowStart: number;
  count: number;
};

const store = new Map<string, ClientWindow>();

function serverNowMs(): number {
  return Date.now();
}

function admit(clientId: string): {
  allowed: boolean;
  remaining: number;
  resetAt: number;
  retryAfter?: number;
} {
  const now = serverNowMs();
  let window = store.get(clientId);

  if (!window || now - window.windowStart >= WINDOW_MS) {
    window = { windowStart: now, count: 0 };
  }

  if (window.count >= LIMIT) {
    const resetAt = window.windowStart + WINDOW_MS;
    const retryAfter = Math.max(1, Math.ceil((resetAt - now) / 1000));
    store.set(clientId, window);
    return { allowed: false, remaining: 0, resetAt, retryAfter };
  }

  window.count += 1;
  store.set(clientId, window);
  const resetAt = window.windowStart + WINDOW_MS;
  return { allowed: true, remaining: LIMIT - window.count, resetAt };
}

Bun.serve({
  port,
  fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/clock") {
      return Response.json({ now_ms: serverNowMs() }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/resource") {
      const clientId = request.headers.get("x-client-id");
      if (!clientId) {
        return Response.json({ error: "missing_client_id" }, { status: 400 });
      }

      // Ignore client-supplied clock hints (skew must not grant extra budget).
      void request.headers.get("x-client-time");

      const outcome = admit(clientId);
      const headers: Record<string, string> = {
        "X-RateLimit-Limit": String(LIMIT),
        "X-RateLimit-Remaining": String(outcome.remaining),
        "X-RateLimit-Reset": String(Math.ceil(outcome.resetAt / 1000)),
      };

      if (!outcome.allowed) {
        headers["Retry-After"] = String(outcome.retryAfter ?? 1);
        return Response.json({ error: "rate_limited" }, { status: 429, headers });
      }

      return Response.json({ ok: true }, { status: 200, headers });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`distributed-fairness reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
